class Solution {
    public int minChanges(int[] nums, int k) {
        int changes = 0;
        for (int i = 0; i <= nums.length - k; i++) {
            int xor = 0;
            for (int j = i; j < i + k; j++) {
                xor ^= nums[j];
            }
            if (xor != 0) {
                changes++;
            }
        }
        return changes;
    }
}
